SELECT Item.[Trademark Code], [DDT_Picking Header].No_, [Sales Line].[customer order ref_], [Sales Line].[Document No_] AS OrderNo, Item.[Model Item No_], Item.[Description 2], [DDT_Picking Line].[Variable Code 01] AS Color, [DDT_Picking Line].[Variable Code 02] AS [Size], [Variable Code].Description AS [Color Description], [NavisionEan-step0].[Cross-Reference No_] AS EAN, [NavisionEan-step0-UPC].[Cross-Reference No_] AS UPC, Val([ddt_picking line.quantity]) AS qtyReadyForShipping
FROM ((((([DDT_Picking Header] INNER JOIN [DDT_Picking Line] ON ([DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) AND ([DDT_Picking Header].[Document Type] = [DDT_Picking Line].[Document Type])) INNER JOIN Item ON [DDT_Picking Line].No_ = Item.No_) INNER JOIN [Sales Line] ON ([DDT_Picking Line].[Order Line No_] = [Sales Line].[Line No_]) AND ([DDT_Picking Line].[Order No_] = [Sales Line].[Document No_])) LEFT JOIN [NavisionEan-step0] ON [DDT_Picking Line].No_ = [NavisionEan-step0].[Item No_]) LEFT JOIN [NavisionEan-step0-UPC] ON [DDT_Picking Line].No_ = [NavisionEan-step0-UPC].[Item No_]) LEFT JOIN [Variable Code] ON ([DDT_Picking Line].[Variable Code 01] = [Variable Code].[Variable Code]) AND ([DDT_Picking Line].[Variable Group 01] = [Variable Code].[Variable Group])
WHERE ((([DDT_Picking Line].[season code])=[FORMS]![PRINCIPALE]![FiltroStagioneEAN2]) AND (([DDT_Picking Header].[Sell-to Customer No_])=[FORMS]![PRINCIPALE]![FILTROCLIENTEEAN]) AND (([DDT_Picking Header].status)=1 Or ([DDT_Picking Header].status)=41 Or ([DDT_Picking Header].status)=42) AND (([DDT_Picking Header].[Document Type])=0) AND ((Item.[advertising material])=0) AND (([DDT_Picking Line].Type)=2));

